from typing import Dict, Any, Optional, Tuple

def validate_user_registration() -> Tuple[Optional[Dict[str, Any]], Optional[str]]:
    try:
        data = request.get_json()
        if not data:
            return None, "No JSON data provided"

        required_fields = ['name', 'email', 'password']
        for field in required_fields:
            if field not in data:
                return None, f"Missing required field: {field}"

        if not isinstance(data['name'], str) or not data['name'].strip():
            return None, "Name must be a non-empty string"

        if not isinstance(data['email'], str) or not data['email'].strip():
            return None, "Email must be a non-empty string"

        if not isinstance(data['password'], str) or len(data['password']) < 8:
            return None, "Password must be a string with at least 8 characters"

        return {
            'name': data['name'].strip(),
            'email': data['email'].strip(),
            'password': data['password']
        }, None

    except json.JSONDecodeError:
        return None, "Invalid JSON format"
    except Exception as e:
        return None, f"Unexpected error: {str(e)}"
