import pytest

def convert_temperature(value, from_scale, to_scale):
    if from_scale == to_scale:
        return value
    if from_scale == 'C' and to_scale == 'F':
        return (value * 9/5) + 32
    if from_scale == 'F' and to_scale == 'C':
        return (value - 32) * 5/9
    raise ValueError("Invalid conversion")

@pytest.mark.parametrize("value, from_scale, to_scale, expected", [
    (0, 'C', 'F', 32),
    (100, 'C', 'F', 212),
    (32, 'F', 'C', 0),
    (212, 'F', 'C', 100),
    (37, 'C', 'F', 98.6),
    (98.6, 'F', 'C', 37),
])
def test_convert_temperature(value, from_scale, to_scale, expected):
    result = convert_temperature(value, from_scale, to_scale)
    assert result == pytest.approx(expected, abs=0.1)
